        long a = i >= 0 ? dp1[i] + nums1[i] : Long.MIN_VALUE;
        long b = j >= 0 ? dp2[j] + nums2[j] : Long.MIN_VALUE;
        Set<Integer> seen = new HashSet<>();
        if (a > b) {
